// Type declarations for @formatjs/intl-pluralrules sub-path imports.
// The package ships no bundled type stubs for /polyfill.js and /locale-data/*.js,
// so TypeScript would error on the side-effect imports in intlPolyfill.config.ts.
declare module '@formatjs/intl-pluralrules/polyfill.js'
declare module '@formatjs/intl-pluralrules/locale-data/*.js'
